### 2. C/‑C++ stub file (`blockscic_stubs.cpp`)

> **NOTE** – The file must be compiled as *C++* (e.g. `ocamlopt -ccopt -std=c++17 …`),
> because it includes the BlockSci C++ headers and uses `new`/`delete`.

```cpp
/* ----------------------------------------------------------------------
   blockscic_stubs.cpp –  OCaml <-> BlockSci glue
   ---------------------------------------------------------------------- */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <blocksci/chain.hpp>          // <-- the public BlockSci header
#include <blocksci/cluster.hpp>        // (any other needed headers)

using namespace blocksci;

/* --------------------------------------------------------------
   Global state
   -------------------------------------------------------------- */
static std::unique_ptr<Chain> g_chain;   // owned by the binding

/* --------------------------------------------------------------
   OCaml custom block for a BlockSci ``Block`` pointer
   -------------------------------------------------------------- */
typedef struct {
    Block *ptr;               // pointer to a *heap* copy of the block
} block_wrapper;

/* Finaliser – called when the OCaml value becomes unreachable */
static void block_finalize(value v) {
    block_wrapper *w = (block_wrapper *)Data_custom_val(v);
    delete w->ptr;            // free the C++ object
}

/* Custom operations table */
static struct custom_operations block_ops = {
    "org.blockscic.block",
    block_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* Helper: allocate a fresh OCaml value that wraps a *copy* of a Block */
static value ocaml_wrap_block(const Block &src) {
    value v = caml_alloc_custom(&block_ops, sizeof(block_wrapper), 0, 1);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v);
    w->ptr = new Block(src);            // copy the block (cheap: block is small)
    return v;
}

/* --------------------------------------------------------------
   Accessor implementations (height, hash, …)
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_block_height(value v_block) {
    CAMLparam1(v_block);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v_block);
    CAMLreturn(Val_int(w->ptr->height()));
}

extern "C" CAMLprim value caml_block_hash(value v_block) {
    CAMLparam1(v_block);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v_block);
    std::string h = w->ptr->hash().to_hex();   // 64‑char hex string
    CAMLreturn(caml_copy_string(h.c_str()));
}

extern "C" CAMLprim value caml_block_timestamp(value v_block) {
    CAMLparam1(v_block);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v_block);
    CAMLreturn(caml_copy_double(w->ptr->timestamp()));
}

extern "C" CAMLprim value caml_block_tx_count(value v_block) {
    CAMLparam1(v_block);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v_block);
    CAMLreturn(Val_int(w->ptr->tx_count()));
}

/* --------------------------------------------------------------
   Initialisation
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_blockscic_init(value v_path) {
    CAMLparam1(v_path);
    const char *path = String_val(v_path);
    try {
        g_chain = std::make_unique<Chain>(path);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   iter_blocks – the hot loop
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_blockscic_iter_blocks(value v_cb) {
    CAMLparam1(v_cb);
    if (!g_chain) caml_failwith("BlockSci not initialised – call Blockscic.init first");

    /* The iterator from BlockSci */
    for (auto it = g_chain->begin(); it != g_chain->end(); ++it) {
        /* 1. copy the block and wrap it */
        value v_block = ocaml_wrap_block(*it);

        /* 2. invoke the OCaml callback */
        /*   caml_callback_exn returns the exception value (or Val_int(0) if none) */
        value result = caml_callback_exn(v_cb, v_block);
        if (Is_exception_result(result)) {
            /* Propagate the exception to the caller – the block will be
               freed by the finaliser when the OCaml stack unwinds. */
            caml_raise(result);
        }
        /* The OCaml callback may have kept a reference to v_block; the
           finaliser will clean it up later.  If the user wants to free it
           immediately they can call Blockscic.release. */
    }
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   iter_blocks_raw – field‑only version (no custom block allocation)
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_blockscic_iter_blocks_raw(value v_cb) {
    CAMLparam1(v_cb);
    if (!g_chain) caml_failwith("BlockSci not initialised – call Blockscic.init first");

    for (auto it = g_chain->begin(); it != g_chain->end(); ++it) {
        const Block &b = *it;

        /* Build the four arguments */
        value v_height    = Val_int(b.height());
        std::string h = b.hash().to_hex();
        value v_hash      = caml_copy_string(h.c_str());
        value v_timestamp = caml_copy_double(b.timestamp());
        value v_tx_cnt    = Val_int(b.tx_count());

        /* Call the OCaml function with labelled arguments.
           We use caml_callback3 because the callback expects a tuple
           (height, hash, timestamp, tx_count). */
        value result = caml_callback3_exn(v_cb, v_height, v_hash, v_timestamp);
        /* caml_callback3_exn returns an exception value if the callback
           raised – we need to add the fourth argument manually. */
        if (Is_exception_result(result)) caml_raise(result);

        /* Apply the fourth argument (tx_count) */
        result = caml_callback_exn(v_cb, v_tx_cnt);
        if (Is_exception_result(result)) caml_raise(result);
    }
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   release – explicit finaliser call
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_blockscic_release(value v_block) {
    CAMLparam1(v_block);
    block_wrapper *w = (block_wrapper *)Data_custom_val(v_block);
    delete w->ptr;
    w->ptr = nullptr;          // mark as released
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   Register the primitives with OCaml (no need for a separate .ml file)
   -------------------------------------------------------------- */
static struct caml_named_value {
    const char *name;
    value (*fn)(value);
} caml_prims[] = {
    {"Blockscic.init",                caml_blockscic_init},
    {"Blockscic.iter_blocks",         caml_blockscic_iter_blocks},
    {"Blockscic.iter_blocks_raw",     caml_blockscic_iter_blocks_raw},
    {"Blockscic.release",             caml_blockscic_release},
    {"Blockscic.block_height",        caml_block_height},
    {"Blockscic.block_hash",          caml_block_hash},
    {"Blockscic.block_timestamp",     caml_block_timestamp},
    {"Blockscic.block_tx_count",      caml_block_tx_count},
    {nullptr, nullptr}
};

extern "C" CAMLprim value caml_register_primitives(value unit) {
    CAMLparam1(unit);
    for (int i = 0; caml_prims[i].name != nullptr; ++i) {
        caml_register_named_value(caml_prims[i].name, caml_prims[i].fn);
    }
    CAMLreturn(Val_unit);
}
```

**Explanation of the stub design**

| Concern | Design choice | Rationale |
|---------|---------------|-----------|
| **Zero‑copy iteration** | The hot loop lives in C++ (`for (auto it = …)`), the OCaml callback is invoked *inside* that loop. | No intermediate OCaml list is built; the iterator runs at native speed. |
| **User‑provided callback** | The callback is passed as a regular OCaml value (`value v_cb`). The stub calls `caml_callback_exn`. | This gives the user full OCaml expressiveness (they can pattern‑match, allocate, call other libraries, etc.). |
| **Per‑block allocation cost** | Two entry points are offered: <br>• `iter_blocks` – returns a fresh custom block (heap‑allocated copy) each iteration.<br>• `iter_blocks_raw` – returns only primitive fields, avoiding the custom‑block allocation. | Users that need the full block can use the first version; analytical workloads that only need a few fields can pick the second version for maximal throughput. |
| **Memory safety** | Each custom block owns a heap‑allocated `Block*`. A finaliser (`block_finalize`) frees it automatically; an explicit `release` is also provided. | Guarantees no memory leak even if the user forgets to free the value. |
| **Thread‑safety / GC interaction** | No `caml_enter_blocking_section`/`caml_leave_blocking_section` is used – the loop runs while the OCaml runtime lock is held. This is fine because the callback itself needs the lock anyway. | Simpler code, and the callback can allocate freely; the runtime can still pre‑empt the loop for GC because the lock is re‑entrant. |
| **Exception propagation** | The stub checks `Is_exception_result` after each callback and re‑raises it with `caml_raise`. | Guarantees that a user‑raised exception aborts the iteration promptly and propagates back to OCaml code. |
| **Initialisation** | A single `init` function stores a `std::unique_ptr<Chain>` in a static variable. | Guarantees that the heavy database loading happens once, and the pointer is available to all later calls. |
| **Linkage** | The file is compiled as C++ (`.cpp`) and exported with `extern "C"` wrappers, so the OCaml runtime can find the symbols. | Needed because BlockSci’s API is C++. |

--------------------------------------------------------------------
### 3. How to compile & use

```sh
# compile the stub (adjust include paths to your BlockSci installation)
ocamlopt -c -ccopt -I/path/to/blocksci/include blockscic_stubs.cpp
# compile the interface (no .ml implementation – we only need the .mli)
ocamlopt -c blockscic.mli

# Build a library (static or shared)
ocamlopt -a -o libblockscic.cmxa blockscic.cmx blockscic_stubs.o \
        -cclib -lblocksci   # link with the BlockSci library

# In an OCaml program:
# --------------------------------------------------------------
#   #require "blockscic";;
#   Blockscic.init "/path/to/blocksci/database";;
#
#   let print_block b =
#     Printf.printf "height=%d hash=%s tx=%d\n"
#       (Blockscic.height b)
#       (Blockscic.hash b)
#       (Blockscic.tx_count b)
#   in
#   Blockscic.iter_blocks print_block
#
#   (* or the raw‑field version *)
#   Blockscic.iter_blocks_raw
#     (fun ~height ~hash ~timestamp ~tx_count ->
#        Printf.printf "h=%d hsh=%s ts=%f tx=%d\n"
#          height hash timestamp tx_count)
# --------------------------------------------------------------
```

With this binding the hot iteration runs at native C++ speed, while the user can write any OCaml code they like inside the callback. The two entry points (`iter_blocks` and `iter_blocks_raw`) give a trade‑off between flexibility (full `block` value) and raw performance (field‑only callback). The design mirrors what libraries such as **Polars** or **pandas** do for per‑row operations, but is tailored to the BlockSci C++ iterator and the OCaml runtime.
